insert into public.hechos (id, numero, ordinal, capitulo_id, resumen, texto_completo, texto_completo_html, titulo_corto, nota_abogado)
select id, numero, ordinal, capitulo_id, resumen, texto_completo, texto_completo_html, titulo_corto, nota_abogado
from jsonb_to_recordset($hechos$[{"id":"hecho-19","numero":19,"ordinal":"DECIMONOVENO","capitulo_id":"cap-4","resumen":"Los montos pagados a Pedro variaban cada mes segun la rentabilidad del negocio, lo que es consistente con participacion en utilidades y NO con honorarios fijos por prestacion de servicios. Se acreditan **14 transferencias bancarias a la cuenta person...","texto_completo":"**HECHO DECIMONOVENO.** Los montos pagados a Pedro variaban cada mes segun la rentabilidad del negocio, lo que es consistente con participacion en utilidades y NO con honorarios fijos por prestacion de servicios. Se acreditan **14 transferencias bancarias a la cuenta personal Bancolombia 4483 de Pedro Vergara, por un subtotal de $99.319.834 COP**, y adicionalmente pagos canalizados a traves de DOCTOR FLIGHT S.A.S. por **$23.025.231 COP**. En consecuencia, el **total acreditado** a favor de Pedro asciende a **$122.345.065 COP**.\n\n### Transferencias 2024:\n| Fecha transferencia | Monto | Observacion |\n|---------------------|-------|-------------|\n| 07/05/2024 | $1.403.330 | Correspondiente a mayo 2024 |\n| 07/06/2024 | $1.695.423 | Correspondiente a junio 2024 |\n| 01/07/2024 | $4.381.509 | Correspondiente a julio 2024 |\n| 05/08/2024 | $6.315.738 | Correspondiente a agosto 2024 |\n| 19/08/2024 | $100.000 | Pago adicional agosto 2024 |\n| 03/09/2024 | $4.190.223 | Correspondiente a septiembre 2024 |\n| 04/10/2024 | $6.280.685 | Correspondiente a octubre 2024 |\n| **Subtotal 2024** | **$24.366.908** | |\n\n### Transferencias 2025:\n| Fecha transferencia | Monto | Observacion |\n|---------------------|-------|-------------|\n| 05/02/2025 | $16.726.760 | Correspondiente a enero 2025 (20% de $83.633.800 de rentabilidad) |\n| 06/03/2025 | $13.422.192 | Correspondiente a febrero 2025 |\n| 03/04/2025 | $10.865.364 | Correspondiente a marzo 2025 |\n| 09/05/2025 | $12.700.000 | Correspondiente a abril 2025 |\n| 06/06/2025 | $8.298.000 | Correspondiente a mayo 2025 |\n| 02/07/2025 | $5.490.610 | Correspondiente a junio 2025 |\n| 05/08/2025 | $7.450.000 | Correspondiente a julio 2025 |\n| **Subtotal 2025** | **$74.952.926** | |\n\n| **SUBTOTAL CUENTA PERSONAL** | **$99.319.834** | **14 transferencias documentadas** |\n\nAdicionalmente, Oscar canalizo pagos a la cuenta de DOCTOR FLIGHT S.A.S. por al menos los siguientes valores: **FE3 $5.913.415**, **FE4 $8.295.256** transferidos (factura por $8.295.260), **FE5 $8.413.000** transferidos (factura por $8.419.646) y **$403.560** por la venta especial del 31/12/2024 reconocida en chat. Ese bloque suma **$23.025.231 COP**.\n\n| **TOTAL ACREDITADO GLOBAL** | **$122.345.065** | **cuenta personal + Doctor Flight S.A.S.** |\n\nLas cuentas de cobro NO dicen \"prestacion de servicios\". El objeto es generico: \"gestion de redes y campanas publicitarias paretomed_1\". Las transferencias personales estan acreditadas con capturas de pantalla de mensajes SMS de Bancolombia, y los pagos canalizados por Doctor Flight quedan reflejados en chat, liquidaciones y facturas. **[P-12, P-13, P-02, P-36, P-37]**","texto_completo_html":"<p><strong>HECHO DECIMONOVENO.</strong> Los montos pagados a Pedro variaban cada mes segun la rentabilidad del negocio, lo que es consistente con participacion en utilidades y NO con honorarios fijos por prestacion de servicios. Se acreditan <strong>14 transferencias bancarias a la cuenta personal Bancolombia 4483 de Pedro Vergara, por un subtotal de $99.319.834 COP</strong>, y adicionalmente pagos canalizados a traves de DOCTOR FLIGHT S.A.S. por <strong>$23.025.231 COP</strong>. En consecuencia, el <strong>total acreditado</strong> a favor de Pedro asciende a <strong>$122.345.065 COP</strong>.</p>\n<h3>Transferencias 2024:</h3>\n<table>\n<thead>\n<tr>\n<th>Fecha transferencia</th>\n<th>Monto</th>\n<th>Observacion</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>07/05/2024</td>\n<td>$1.403.330</td>\n<td>Correspondiente a mayo 2024</td>\n</tr>\n<tr>\n<td>07/06/2024</td>\n<td>$1.695.423</td>\n<td>Correspondiente a junio 2024</td>\n</tr>\n<tr>\n<td>01/07/2024</td>\n<td>$4.381.509</td>\n<td>Correspondiente a julio 2024</td>\n</tr>\n<tr>\n<td>05/08/2024</td>\n<td>$6.315.738</td>\n<td>Correspondiente a agosto 2024</td>\n</tr>\n<tr>\n<td>19/08/2024</td>\n<td>$100.000</td>\n<td>Pago adicional agosto 2024</td>\n</tr>\n<tr>\n<td>03/09/2024</td>\n<td>$4.190.223</td>\n<td>Correspondiente a septiembre 2024</td>\n</tr>\n<tr>\n<td>04/10/2024</td>\n<td>$6.280.685</td>\n<td>Correspondiente a octubre 2024</td>\n</tr>\n<tr>\n<td><strong>Subtotal 2024</strong></td>\n<td><strong>$24.366.908</strong></td>\n<td></td>\n</tr>\n</tbody>\n</table>\n<h3>Transferencias 2025:</h3>\n<table>\n<thead>\n<tr>\n<th>Fecha transferencia</th>\n<th>Monto</th>\n<th>Observacion</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>05/02/2025</td>\n<td>$16.726.760</td>\n<td>Correspondiente a enero 2025 (20% de $83.633.800 de rentabilidad)</td>\n</tr>\n<tr>\n<td>06/03/2025</td>\n<td>$13.422.192</td>\n<td>Correspondiente a febrero 2025</td>\n</tr>\n<tr>\n<td>03/04/2025</td>\n<td>$10.865.364</td>\n<td>Correspondiente a marzo 2025</td>\n</tr>\n<tr>\n<td>09/05/2025</td>\n<td>$12.700.000</td>\n<td>Correspondiente a abril 2025</td>\n</tr>\n<tr>\n<td>06/06/2025</td>\n<td>$8.298.000</td>\n<td>Correspondiente a mayo 2025</td>\n</tr>\n<tr>\n<td>02/07/2025</td>\n<td>$5.490.610</td>\n<td>Correspondiente a junio 2025</td>\n</tr>\n<tr>\n<td>05/08/2025</td>\n<td>$7.450.000</td>\n<td>Correspondiente a julio 2025</td>\n</tr>\n<tr>\n<td><strong>Subtotal 2025</strong></td>\n<td><strong>$74.952.926</strong></td>\n<td></td>\n</tr>\n</tbody>\n</table>\n<p>| <strong>SUBTOTAL CUENTA PERSONAL</strong> | <strong>$99.319.834</strong> | <strong>14 transferencias documentadas</strong> |</p>\n<p>Adicionalmente, Oscar canalizo pagos a la cuenta de DOCTOR FLIGHT S.A.S. por al menos los siguientes valores: <strong>FE3 $5.913.415</strong>, <strong>FE4 $8.295.256</strong> transferidos (factura por $8.295.260), <strong>FE5 $8.413.000</strong> transferidos (factura por $8.419.646) y <strong>$403.560</strong> por la venta especial del 31/12/2024 reconocida en chat. Ese bloque suma <strong>$23.025.231 COP</strong>.</p>\n<p>| <strong>TOTAL ACREDITADO GLOBAL</strong> | <strong>$122.345.065</strong> | <strong>cuenta personal + Doctor Flight S.A.S.</strong> |</p>\n<p>Las cuentas de cobro NO dicen &quot;prestacion de servicios&quot;. El objeto es generico: &quot;gestion de redes y campanas publicitarias paretomed_1&quot;. Las transferencias personales estan acreditadas con capturas de pantalla de mensajes SMS de Bancolombia, y los pagos canalizados por Doctor Flight quedan reflejados en chat, liquidaciones y facturas. <strong>[P-12, P-13, P-02, P-36, P-37]</strong></p>\n","titulo_corto":"Pagos acreditados — $122.3M total","nota_abogado":null},{"id":"hecho-46","numero":46,"ordinal":"CUADRAGESIMOSEXTO","capitulo_id":"cap-13","resumen":"El total acreditado a favor de Pedro asciende a **$122.345.065 COP** entre mayo de 2024 y agosto de 2025, discriminado en (i) **14 transferencias a su cuenta personal** por **$99.319.834 COP** y (ii) **pagos canalizados a traves de DOCTOR FLIGHT S.A....","texto_completo":"**HECHO CUADRAGESIMOSEXTO.** El total acreditado a favor de Pedro asciende a **$122.345.065 COP** entre mayo de 2024 y agosto de 2025, discriminado en (i) **14 transferencias a su cuenta personal** por **$99.319.834 COP** y (ii) **pagos canalizados a traves de DOCTOR FLIGHT S.A.S.** por **$23.025.231 COP**. Si estos pagos representan el 20% de las utilidades netas, la ganancia neta total del negocio durante dicho periodo fue de aproximadamente **$611.725.325 COP**. El subtotal de $99.319.834 corresponde solo a la cuenta personal y NO agota el total recibido por Pedro. Esta cifra es compatible con los ingresos brutos reportados de $709.010.075 COP y refuerza la necesidad de un peritaje contable integral. **[P-36, P-37, P-12, P-02]**\n\n---\n\n## NOTA PARA LOS ABOGADOS: RESUMEN DE LAS PRUEBAS MAS CONTUNDENTES\n\nLas siguientes pruebas son las de mayor poder probatorio:\n\n1. **[P-01] Grabacion telefonica 14/08/2025:** Confesion extrajudicial de Oscar admitiendo la sociedad, el pacto de acciones, y que sus propios abogados y contadores confirmaron la existencia de sociedad de hecho.\n\n2. **[P-11] Carta de Recomendacion firmada por Oscar (27/04/2024):** Documento firmado por el demandado que nombra a Pedro \"Subdirector Academico y Comercial\" - cargo directivo incompatible con prestacion de servicios.\n\n3. **[P-09] Nota manuscrita de Oscar en Acuerdo de Socios:** Oscar admite que el 20% \"no se justifican por una labor que es contratable\".\n\n4. **[P-06 y P-07] Alteracion del Google Doc:** El cambio de \"acciones\" por \"utilidades\" por usuario anonimo evidencia mala fe.\n\n5. **[P-22 y P-23] Certificados DNDA (238 obras):** Pedro registrado como AUTOR/DIRECTOR/PRODUCTOR; Oscar solo como INTERPRETE. Invierte la narrativa de que la PI pertenece exclusivamente a Oscar.\n\n6. **[P-12 y P-13] Cuentas de cobro y liquidaciones:** Los montos variables (de $1.4M a $16.7M) calculados como 20% de ganancia neta son inconsistentes con honorarios fijos de servicios.\n\n7. **[P-14] Contrato de Cuentas en Participacion (Oscar, 22/08/2025):** Usa terminologia de \"socios\" mientras simultaneamente niega la sociedad de hecho, lo cual es contradictorio.\n\n8. **[P-25, P-26] SOPs creados por Pedro:** Demuestran que Pedro diseno la infraestructura operativa del negocio, funcion de socio/director.\n\n9. **[P-19] Constancia de No Conciliacion:** Acredita el agotamiento del requisito de procedibilidad.\n\n10. **[P-20] Certificado Camara de Comercio ParetoMed:** Activos declarados de solo $20M vs. ingresos reales de $709M, evidencia subvaloracion.\n\n11. **[P-50] Audios 13/07/2025 — Oscar exige deberes de socio sobre herramienta tecnologica:** Oscar reclama a Pedro obligaciones propias de un socio respecto a una herramienta tecnologica desarrollada por Pedro (*\"como le vas a licenciar eso a una empresa de la cual eres socio\"*). Paradojicamente, al exigirle deberes societarios, Oscar RECONOCE que Pedro es socio con obligaciones fiduciarias hacia el negocio. Confesion extrajudicial devastadora.\n\n---","texto_completo_html":"<p><strong>HECHO CUADRAGESIMOSEXTO.</strong> El total acreditado a favor de Pedro asciende a <strong>$122.345.065 COP</strong> entre mayo de 2024 y agosto de 2025, discriminado en (i) <strong>14 transferencias a su cuenta personal</strong> por <strong>$99.319.834 COP</strong> y (ii) <strong>pagos canalizados a traves de DOCTOR FLIGHT S.A.S.</strong> por <strong>$23.025.231 COP</strong>. Si estos pagos representan el 20% de las utilidades netas, la ganancia neta total del negocio durante dicho periodo fue de aproximadamente <strong>$611.725.325 COP</strong>. El subtotal de $99.319.834 corresponde solo a la cuenta personal y NO agota el total recibido por Pedro. Esta cifra es compatible con los ingresos brutos reportados de $709.010.075 COP y refuerza la necesidad de un peritaje contable integral. <strong>[P-36, P-37, P-12, P-02]</strong></p>\n<hr>\n<h2>NOTA PARA LOS ABOGADOS: RESUMEN DE LAS PRUEBAS MAS CONTUNDENTES</h2>\n<p>Las siguientes pruebas son las de mayor poder probatorio:</p>\n<ol>\n<li>\n<p><strong>[P-01] Grabacion telefonica 14/08/2025:</strong> Confesion extrajudicial de Oscar admitiendo la sociedad, el pacto de acciones, y que sus propios abogados y contadores confirmaron la existencia de sociedad de hecho.</p>\n</li>\n<li>\n<p><strong>[P-11] Carta de Recomendacion firmada por Oscar (27/04/2024):</strong> Documento firmado por el demandado que nombra a Pedro &quot;Subdirector Academico y Comercial&quot; - cargo directivo incompatible con prestacion de servicios.</p>\n</li>\n<li>\n<p><strong>[P-09] Nota manuscrita de Oscar en Acuerdo de Socios:</strong> Oscar admite que el 20% &quot;no se justifican por una labor que es contratable&quot;.</p>\n</li>\n<li>\n<p><strong>[P-06 y P-07] Alteracion del Google Doc:</strong> El cambio de &quot;acciones&quot; por &quot;utilidades&quot; por usuario anonimo evidencia mala fe.</p>\n</li>\n<li>\n<p><strong>[P-22 y P-23] Certificados DNDA (238 obras):</strong> Pedro registrado como AUTOR/DIRECTOR/PRODUCTOR; Oscar solo como INTERPRETE. Invierte la narrativa de que la PI pertenece exclusivamente a Oscar.</p>\n</li>\n<li>\n<p><strong>[P-12 y P-13] Cuentas de cobro y liquidaciones:</strong> Los montos variables (de $1.4M a $16.7M) calculados como 20% de ganancia neta son inconsistentes con honorarios fijos de servicios.</p>\n</li>\n<li>\n<p><strong>[P-14] Contrato de Cuentas en Participacion (Oscar, 22/08/2025):</strong> Usa terminologia de &quot;socios&quot; mientras simultaneamente niega la sociedad de hecho, lo cual es contradictorio.</p>\n</li>\n<li>\n<p><strong>[P-25, P-26] SOPs creados por Pedro:</strong> Demuestran que Pedro diseno la infraestructura operativa del negocio, funcion de socio/director.</p>\n</li>\n<li>\n<p><strong>[P-19] Constancia de No Conciliacion:</strong> Acredita el agotamiento del requisito de procedibilidad.</p>\n</li>\n<li>\n<p><strong>[P-20] Certificado Camara de Comercio ParetoMed:</strong> Activos declarados de solo $20M vs. ingresos reales de $709M, evidencia subvaloracion.</p>\n</li>\n<li>\n<p><strong>[P-50] Audios 13/07/2025 — Oscar exige deberes de socio sobre herramienta tecnologica:</strong> Oscar reclama a Pedro obligaciones propias de un socio respecto a una herramienta tecnologica desarrollada por Pedro (<em>&quot;como le vas a licenciar eso a una empresa de la cual eres socio&quot;</em>). Paradojicamente, al exigirle deberes societarios, Oscar RECONOCE que Pedro es socio con obligaciones fiduciarias hacia el negocio. Confesion extrajudicial devastadora.</p>\n</li>\n</ol>\n<hr>\n","titulo_corto":"Pagos acreditados — $122.3M en dos canales","nota_abogado":null}]$hechos$::jsonb)
  as x(id text, numero integer, ordinal text, capitulo_id text, resumen text, texto_completo text, texto_completo_html text, titulo_corto text, nota_abogado text)
on conflict (id) do update set
  numero = excluded.numero,
  ordinal = excluded.ordinal,
  capitulo_id = excluded.capitulo_id,
  resumen = excluded.resumen,
  texto_completo = excluded.texto_completo,
  texto_completo_html = excluded.texto_completo_html,
  titulo_corto = excluded.titulo_corto,
  nota_abogado = excluded.nota_abogado;

insert into public.pruebas (id, descripcion, tipo, categoria)
select id, descripcion, tipo, categoria
from jsonb_to_recordset($pruebas$[{"id":"P-36","descripcion":"Transferencias bancarias Bancolombia cuenta 4483 de Pedro Vergara (14 transferencias a cuenta personal, $99.319.834 subtotal)","tipo":"Prueba financiera","categoria":null}]$pruebas$::jsonb)
  as x(id text, descripcion text, tipo text, categoria text)
on conflict (id) do update set
  descripcion = excluded.descripcion,
  tipo = excluded.tipo,
  categoria = excluded.categoria;

delete from public.hecho_pruebas where hecho_id in (select jsonb_array_elements_text($ids$["hecho-19","hecho-46"]$ids$::jsonb));
insert into public.hecho_pruebas (hecho_id, prueba_id)
select hecho_id, prueba_id
from jsonb_to_recordset($rel$[{"hecho_id":"hecho-19","prueba_id":"P-12"},{"hecho_id":"hecho-19","prueba_id":"P-13"},{"hecho_id":"hecho-19","prueba_id":"P-02"},{"hecho_id":"hecho-19","prueba_id":"P-36"},{"hecho_id":"hecho-19","prueba_id":"P-37"},{"hecho_id":"hecho-46","prueba_id":"P-36"},{"hecho_id":"hecho-46","prueba_id":"P-37"},{"hecho_id":"hecho-46","prueba_id":"P-12"},{"hecho_id":"hecho-46","prueba_id":"P-02"},{"hecho_id":"hecho-46","prueba_id":"P-01"},{"hecho_id":"hecho-46","prueba_id":"P-11"},{"hecho_id":"hecho-46","prueba_id":"P-09"},{"hecho_id":"hecho-46","prueba_id":"P-06"},{"hecho_id":"hecho-46","prueba_id":"P-07"},{"hecho_id":"hecho-46","prueba_id":"P-22"},{"hecho_id":"hecho-46","prueba_id":"P-23"},{"hecho_id":"hecho-46","prueba_id":"P-13"},{"hecho_id":"hecho-46","prueba_id":"P-14"},{"hecho_id":"hecho-46","prueba_id":"P-25"},{"hecho_id":"hecho-46","prueba_id":"P-26"},{"hecho_id":"hecho-46","prueba_id":"P-19"},{"hecho_id":"hecho-46","prueba_id":"P-20"},{"hecho_id":"hecho-46","prueba_id":"P-50"}]$rel$::jsonb)
  as x(hecho_id text, prueba_id text)
on conflict do nothing;

delete from public.fragmentos_clave where hecho_id in (select jsonb_array_elements_text($ids$["hecho-19","hecho-46"]$ids$::jsonb));
insert into public.fragmentos_clave (hecho_id, cita, fuente, linea, fecha, autor, relevancia)
select hecho_id, cita, fuente, linea, fecha, autor, relevancia
from jsonb_to_recordset($frag$[{"hecho_id":"hecho-19","cita":"14 transferencias bancarias de la cuenta de OSCAR MALDONADO a la cuenta Bancolombia 4483 de Pedro Vergara, por un subtotal personal de $99.319.834 COP","fuente":"doc-pagos-bancolombia","linea":null,"fecha":"mayo 2024 - agosto 2025","autor":"Oscar Maldonado","relevancia":"Subtotal de transferencias a la cuenta personal de Pedro; con los pagos via Doctor Flight el total acreditado asciende a $122.345.065"},{"hecho_id":"hecho-19","cita":"31/12/2024 | $8.413.000 | Diciembre 2024 (pago adelantado)","fuente":"doc-pagos-bancolombia","linea":null,"fecha":null,"autor":null,"relevancia":"Comprobante bancario de transferencia de diciembre 2024 como parte del total de 14 pagos documentados — P-36"},{"hecho_id":"hecho-46","cita":"14 transferencias bancarias de la cuenta de OSCAR MALDONADO a la cuenta Bancolombia 4483 de Pedro Vergara, por un subtotal personal de $99.319.834 COP","fuente":"doc-pagos-bancolombia","linea":null,"fecha":"mayo 2024 - agosto 2025","autor":"Oscar Maldonado","relevancia":"Las 14 transferencias por SMS acreditan el subtotal personal; al sumar Doctor Flight el total recibido por Pedro asciende a $122.345.065 y se refuerza la variabilidad propia de utilidades"},{"hecho_id":"hecho-46","cita":"como le vas a licenciar eso a una empresa de la cual eres socio","fuente":null,"linea":null,"fecha":null,"autor":null,"relevancia":null}]$frag$::jsonb)
  as x(hecho_id text, cita text, fuente text, linea text, fecha text, autor text, relevancia text);

commit;